      "path": "src/modules/projects/service.js",
      "content": "const { randomUUID } = require('../../lib/id');

let projectsStore = [];

const getAllProjects = () => {
  return Promise.resolve(projectsStore);
};

const createProject = (name) => {
  const existingProject = projectsStore.find(project => project.name === name);
  if (existingProject) {
    throw { code: 'DUPLICATE_PROJECT' };
  }

  const newProject = {
    id: randomUUID(),
    name,
    tasks: [],
    members: []
  };

  projectsStore.push(newProject);
  return Promise.resolve(newProject);
};

const getProjectById = (projectId) => {
  const project = projectsStore.find(project => project.id === projectId);
  return Promise.resolve(project);
};

module.exports = { getAllProjects, createProject, getProjectById };
